screens.custom_css:
[selector="text-invalid"] {
  color: #EC5962;
  font-size: .875em;
}

[selector="list-actividades-asegurado"] .data-table {
  display: flex;
  flex-direction: column;
}

[selector="list-actividades-asegurado"] .data-table > .row.mb-2.ml-0.mr-0 {
  order: 1;
}

[selector="list-actividades-asegurado"] .data-table > .d-flex.justify-content-between.align-items-center {
  order: 2;
  width: 100%;
  justify-content: flex-end !important;
  margin: .25rem 0 .5rem;
}

[selector="list-actividades-asegurado"] .data-table > .d-flex.justify-content-between.align-items-center > .col {
  flex: 0 0 auto;
  max-width: unset;
}
[selector="list-actividades-asegurado"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-left {
  display: none;
}
[selector="list-actividades-asegurado"] .data-table > .d-flex.justify-content-between.align-items-center > .col.text-right {
  display: block;
}

[selector="list-actividades-asegurado"] .data-table > .d-flex [data-cy="add-row"].btn {
  font-weight: 600;
  border-radius: 6px;
  padding: .35rem .9rem;
  box-shadow: 0 2px 8px rgba(0,0,0,.08);
  margin: 0 -10px 10px 0;
}

[selector="list-actividades-asegurado"] .data-table > table.record-list-table-secondary {
  order: 3;
}

@media (min-width: 576px) {
  [selector="list-actividades-asegurado"] .data-table > .d-flex.justify-content-between.align-items-center {
    margin-bottom: .75rem;
  }
}


[selector="list-actividades-asegurado"] table.record-list-table-secondary thead th.text-right > div {
  position: relative;
  color: transparent;
}
[selector="list-actividades-asegurado"] table.record-list-table-secondary thead th.text-right > div::after {
  content: "Acciones";
  position: absolute;
  right: 0; left: auto; top: 0;
  color: #2c3e50;
  font-weight: 600;
  text-align: right;
  width: 100%;
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions [title="Editar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(17%) sepia(22%) saturate(2557%) hue-rotate(171deg) brightness(92%) contrast(92%);
}
[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions [title="Editar"]:hover img{
  filter: invert(13%) sepia(27%) saturate(2412%) hue-rotate(173deg) brightness(80%) contrast(95%);
  transform: translateY(-1px);
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions [title="Eliminar"] img{
  transition: filter .15s ease, transform .12s ease;
  filter: invert(14%) sepia(90%) saturate(6268%) hue-rotate(356deg) brightness(90%) contrast(104%);
}
[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions [title="Eliminar"]:hover img{
  filter: invert(11%) sepia(93%) saturate(5530%) hue-rotate(355deg) brightness(70%) contrast(110%);
  transform: translateY(-1px);
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions .btn:focus img{
  outline: none;
  filter: drop-shadow(0 0 0.25rem rgba(15,76,129,.35));
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"]{
  overflow: visible; 
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions{
  position: relative; 
  z-index: 1;
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions .popover-content{
  position: absolute;
  right: 0;
  top: auto;
  bottom: calc(100% + 8px);
  z-index: 2000;

  margin-top: 0 !important;
  background: #fff;
  border: 1px solid #e5e7eb;
  border-radius: 8px;
  padding: 10px 12px;
  box-shadow: 0 10px 24px rgba(0,0,0,.12);
  width: max-content;
  max-width: clamp(220px, 40vw, 320px);
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions .popover-content::before{
  content: "";
  position: absolute;
  bottom: -6px;
  right: 14px;
  border-width: 6px;
  border-style: solid;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}

[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions .popover-content.popover--top{
  top: auto;
  bottom: calc(100% + 8px);
}
[selector="list-actividades-asegurado"] td[aria-colindex="8"] .actions .popover-content.popover--top::before{
  top: auto;
  bottom: -6px;
  border-color: #fff transparent transparent transparent;
  filter: drop-shadow(0 1px 0 #e5e7eb);
}


[selector="list-actividades-asegurado"] .actions .popover-content p,
[selector="list-actividades-asegurado"] .actions .popover-content .btn {
  position: relative;
  color: transparent !important;
  font-size: 0 !important;
}

[selector="list-actividades-asegurado"] .actions .popover-content p::after {
  content: "¿Confirmas que deseas eliminar este registro?";
  font-size: 0.95rem;
  color: #111827;
  line-height: 1.35;
  display: block;
}

[selector="list-actividades-asegurado"] .actions .popover-content .btn.btn-light::after {
  content: "Cancelar";
  font-size: 0.875rem;
